// shard-knot: split a single .knot file into per-layer-range sub-knots.
//
// Usage:
//   shard-knot \
//       --input ./tinyllama-1.1b.knot \
//       --output-dir ./shards/ \
//       --shards "0..10:entry,11..21:exit"
//
// Each output shard is itself a valid .knot file. Header (magic + version +
// codec marker) is copied verbatim from the source. Metadata is the original
// `KnotConfig` plus a `tensors` map filtered to the tensors this shard owns,
// with offsets recomputed against the new sequential payload.
//
// This binary is native-only: it depends on memmap2 + std::fs. Wired into
// Cargo.toml as `[[bin]] name = "shard-knot"`. Not built on wasm32.
//
// Residency rules (see request brief):
//   - entry: token_embd_weight + blk_L_* for L in [start, end)
//   - exit:  blk_L_* for L in [start, end) + output_norm_weight + output_weight (if present)
//   - mid:   blk_L_* for L in [start, end)
//
// Out of scope for this binary: R2 upload, signing, content addressing.

use distributed_inference::loader::TensorInfo;
use memmap2::Mmap;
use serde::Serialize;
use std::collections::{BTreeMap, HashMap};
use std::fs::{self, File};
use std::io::Write;
use std::path::{Path, PathBuf};

// ─────────────────────────────────────────────────────────────────────────
// CLI
// ─────────────────────────────────────────────────────────────────────────

#[derive(Debug)]
struct Args {
    input: PathBuf,
    output_dir: PathBuf,
    shards: String,
}

fn parse_args() -> Result<Args, String> {
    let mut input: Option<PathBuf> = None;
    let mut output_dir: Option<PathBuf> = None;
    let mut shards: Option<String> = None;

    let argv: Vec<String> = std::env::args().collect();
    let mut i = 1;
    while i < argv.len() {
        let a = &argv[i];
        match a.as_str() {
            "--input" => {
                i += 1;
                input = Some(PathBuf::from(argv.get(i).ok_or("--input missing value")?));
            }
            "--output-dir" => {
                i += 1;
                output_dir = Some(PathBuf::from(
                    argv.get(i).ok_or("--output-dir missing value")?,
                ));
            }
            "--shards" => {
                i += 1;
                shards = Some(argv.get(i).ok_or("--shards missing value")?.to_string());
            }
            "--help" | "-h" => {
                eprintln!(
                    "shard-knot --input PATH --output-dir PATH --shards \"START..END:ROLE,...\""
                );
                std::process::exit(0);
            }
            other => return Err(format!("unknown arg: {}", other)),
        }
        i += 1;
    }

    Ok(Args {
        input: input.ok_or("--input required")?,
        output_dir: output_dir.ok_or("--output-dir required")?,
        shards: shards.ok_or("--shards required")?,
    })
}

// ─────────────────────────────────────────────────────────────────────────
// Shard spec
// ─────────────────────────────────────────────────────────────────────────

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum ShardRole {
    Entry,
    Exit,
    Mid,
}

impl ShardRole {
    fn parse(s: &str) -> Result<Self, String> {
        match s {
            "entry" => Ok(ShardRole::Entry),
            "exit" => Ok(ShardRole::Exit),
            "mid" => Ok(ShardRole::Mid),
            other => Err(format!("unknown role: {}", other)),
        }
    }
    fn as_str(&self) -> &'static str {
        match self {
            ShardRole::Entry => "entry",
            ShardRole::Exit => "exit",
            ShardRole::Mid => "mid",
        }
    }
}

#[derive(Debug, Clone)]
pub struct ShardSpec {
    pub start_layer: usize,
    pub end_layer: usize, // exclusive
    pub role: ShardRole,
}

/// Parse `"0..10:entry,11..21:exit"`. End is *inclusive* in CLI form (Station
/// pin convention) but we normalize to half-open [start, end_excl).
pub fn parse_shard_spec(spec: &str, num_layers: usize) -> Result<Vec<ShardSpec>, String> {
    let mut out = Vec::new();
    for chunk in spec.split(',').map(str::trim).filter(|s| !s.is_empty()) {
        let (range, role) = chunk
            .split_once(':')
            .ok_or_else(|| format!("shard '{}' missing ':role'", chunk))?;
        let (lo, hi) = range
            .split_once("..")
            .ok_or_else(|| format!("shard '{}' missing '..' in range", chunk))?;
        let lo: usize = lo
            .trim()
            .parse()
            .map_err(|e| format!("range start: {}", e))?;
        let hi: usize = hi.trim().parse().map_err(|e| format!("range end: {}", e))?;
        if hi < lo {
            return Err(format!("shard '{}': end < start", chunk));
        }
        // CLI uses inclusive end ("0..10" means layers 0 through 10 inclusive
        // when written as `entry: layers 0..10`). Convert to half-open.
        out.push(ShardSpec {
            start_layer: lo,
            end_layer: hi + 1,
            role: ShardRole::parse(role.trim())?,
        });
    }

    validate_shards(&out, num_layers)?;
    Ok(out)
}

fn validate_shards(shards: &[ShardSpec], num_layers: usize) -> Result<(), String> {
    if shards.is_empty() {
        return Err("no shards specified".into());
    }
    let mut sorted = shards.to_vec();
    sorted.sort_by_key(|s| s.start_layer);

    // Coverage + non-overlap.
    let mut cursor = 0usize;
    for s in &sorted {
        if s.start_layer != cursor {
            return Err(format!(
                "shards not contiguous at layer {}; expected start = {}, got {}",
                cursor, cursor, s.start_layer
            ));
        }
        if s.end_layer <= s.start_layer {
            return Err(format!("shard {:?} is empty", s));
        }
        cursor = s.end_layer;
    }
    if cursor != num_layers {
        return Err(format!(
            "shards cover [0, {}) but model has {} layers",
            cursor, num_layers
        ));
    }

    // Role rules.
    let entries: Vec<&ShardSpec> = sorted
        .iter()
        .filter(|s| s.role == ShardRole::Entry)
        .collect();
    let exits: Vec<&ShardSpec> = sorted
        .iter()
        .filter(|s| s.role == ShardRole::Exit)
        .collect();
    if entries.len() != 1 {
        return Err(format!(
            "exactly one entry shard required (got {})",
            entries.len()
        ));
    }
    if exits.len() != 1 {
        return Err(format!(
            "exactly one exit shard required (got {})",
            exits.len()
        ));
    }
    if entries[0].start_layer != 0 {
        return Err("entry shard must start at layer 0".into());
    }
    if exits[0].end_layer != num_layers {
        return Err(format!(
            "exit shard must end at layer {} (num_layers); ends at {}",
            num_layers, exits[0].end_layer
        ));
    }
    Ok(())
}

// ─────────────────────────────────────────────────────────────────────────
// Manifest
// ─────────────────────────────────────────────────────────────────────────

#[derive(Serialize, Debug)]
pub struct ShardManifestEntry {
    pub filename: String,
    pub start_layer: usize,
    pub end_layer: usize, // exclusive (matches half-open internal repr)
    pub role: String,
    pub tensor_names: Vec<String>,
}

#[derive(Serialize, Debug)]
pub struct Manifest {
    pub source: String,
    /// Original `config` block from the source metadata, echoed verbatim. We
    /// keep it as `serde_json::Value` because the loader's `KnotConfig` is
    /// `Deserialize`-only; round-tripping through JSON preserves any extra
    /// fields newer knots add without forcing a derive change in `loader.rs`.
    pub config: Option<serde_json::Value>,
    pub shards: Vec<ShardManifestEntry>,
}

// ─────────────────────────────────────────────────────────────────────────
// Tensor partitioning
// ─────────────────────────────────────────────────────────────────────────

/// Parse `blk_<L>_*` -> Some(L). Returns None for non-block tensors.
/// Accepts both `blk_3_attn_q_weight` and `blk_3_attn_q_weight.bin` (the
/// `parse_tensors` helper strips `.bin`, but we run directly off the raw
/// metadata JSON so handle either form).
fn layer_index_of(name: &str) -> Option<usize> {
    let rest = name.strip_prefix("blk_")?;
    let underscore = rest.find('_')?;
    rest[..underscore].parse::<usize>().ok()
}

/// Resolve a logical tensor name to the actual metadata key, tolerating the
/// `.bin` suffix the source knot uses (keys are e.g. `token_embd_weight.bin`,
/// not `token_embd_weight`).
fn resolve_key(metadata: &HashMap<String, TensorInfo>, logical: &str) -> Option<String> {
    if metadata.contains_key(logical) {
        return Some(logical.to_string());
    }
    let with_bin = format!("{logical}.bin");
    if metadata.contains_key(&with_bin) {
        return Some(with_bin);
    }
    None
}

/// Given the full tensor map and a shard spec, return the tensor names that
/// belong to this shard.
fn tensors_for_shard(spec: &ShardSpec, metadata: &HashMap<String, TensorInfo>) -> Vec<String> {
    let mut names: Vec<String> = Vec::new();

    // Block tensors: keep if layer in [start, end).
    for name in metadata.keys() {
        if let Some(layer) = layer_index_of(name) {
            if layer >= spec.start_layer && layer < spec.end_layer {
                names.push(name.clone());
            }
        }
    }

    // Resident extras by role. Source knots name tensors with a `.bin` suffix
    // (e.g. `token_embd_weight.bin`), so resolve logical names tolerantly.
    match spec.role {
        ShardRole::Entry => {
            if let Some(k) = resolve_key(metadata, "token_embd_weight") {
                names.push(k);
            }
        }
        ShardRole::Exit => {
            if let Some(k) = resolve_key(metadata, "output_norm_weight") {
                names.push(k);
            }
            // lm-head source: an explicit output_weight if present, otherwise the
            // tied embedding (qwen ties output_weight -> token_embd, so the source
            // ships only token_embd_weight). Without this the exit shard's
            // /lm-head has no weights.
            if let Some(k) = resolve_key(metadata, "output_weight") {
                names.push(k);
            } else if let Some(k) = resolve_key(metadata, "token_embd_weight") {
                names.push(k);
            }
        }
        ShardRole::Mid => {}
    }

    // Stable order: sort lexicographically. Sequential payload offsets follow
    // this order, and the manifest reports the same order.
    names.sort();
    names
}

// ─────────────────────────────────────────────────────────────────────────
// Knot writer
// ─────────────────────────────────────────────────────────────────────────

/// Build a per-shard metadata JSON value: original config + filtered tensors
/// with recomputed sequential offsets. Returns the serialized bytes plus the
/// in-order tensor list (so the writer can stream payload bytes deterministically).
fn build_shard_metadata(
    source_meta: &serde_json::Value,
    source_tensors: &HashMap<String, TensorInfo>,
    tensor_names: &[String],
) -> (Vec<u8>, Vec<(String, TensorInfo, usize /* new offset */)>) {
    let mut tensors_obj = serde_json::Map::new();
    let mut layout: Vec<(String, TensorInfo, usize)> = Vec::with_capacity(tensor_names.len());
    let mut cursor = 0usize;
    for name in tensor_names {
        let info = source_tensors
            .get(name)
            .expect("tensor selected for shard but not in source metadata");
        let mut tinfo_json = serde_json::Map::new();
        tinfo_json.insert("offset".into(), serde_json::Value::from(cursor));
        tinfo_json.insert("length".into(), serde_json::Value::from(info.length));
        tinfo_json.insert(
            "type".into(),
            serde_json::Value::from(info.tensor_type.clone()),
        );
        tensors_obj.insert(name.clone(), serde_json::Value::Object(tinfo_json));
        layout.push((name.clone(), info.clone(), cursor));
        cursor += info.length as usize;
    }

    // Top-level: copy everything from source except `tensors`, then overwrite.
    let mut shard_meta = match source_meta {
        serde_json::Value::Object(map) => map.clone(),
        _ => panic!("knot metadata is not a JSON object"),
    };
    shard_meta.insert("tensors".into(), serde_json::Value::Object(tensors_obj));

    let bytes = serde_json::to_vec(&serde_json::Value::Object(shard_meta))
        .expect("serialize shard metadata");
    (bytes, layout)
}

/// Write a shard `.knot` file: header (magic + version + meta_len + padded
/// metadata + codec marker) followed by the concatenated tensor bytes.
fn write_shard_file(
    out_path: &Path,
    version_le: [u8; 2],
    codec_marker: u8,
    metadata: &[u8],
    layout: &[(String, TensorInfo, usize)],
    src_payload: &[u8],
) -> Result<(), String> {
    let mut f =
        File::create(out_path).map_err(|e| format!("create {}: {}", out_path.display(), e))?;

    // 1. magic
    f.write_all(b"KNOT").map_err(|e| e.to_string())?;
    // 2. version (u16 LE) — preserve from source
    f.write_all(&version_le).map_err(|e| e.to_string())?;
    // 3. metadata length (u32 LE)
    let meta_len = metadata.len() as u32;
    f.write_all(&meta_len.to_le_bytes())
        .map_err(|e| e.to_string())?;
    // 4. metadata JSON
    f.write_all(metadata).map_err(|e| e.to_string())?;
    // 5. pad metadata to 4-byte alignment relative to file start
    //    payload_offset (excluding codec) = (10 + meta_len + 3) & !3
    let unpadded = 10 + metadata.len();
    let aligned = (unpadded + 3) & !3;
    let pad = aligned - unpadded;
    if pad > 0 {
        f.write_all(&vec![0u8; pad]).map_err(|e| e.to_string())?;
    }
    // 6. codec marker (1 byte) — preserve from source
    f.write_all(&[codec_marker]).map_err(|e| e.to_string())?;
    // 7. payload: concatenate tensor bytes in metadata order
    for (_, info, _new_off) in layout {
        let start = info.offset as usize;
        let end = start + info.length as usize;
        f.write_all(&src_payload[start..end])
            .map_err(|e| e.to_string())?;
    }

    f.flush().map_err(|e| e.to_string())?;
    Ok(())
}

// ─────────────────────────────────────────────────────────────────────────
// Top-level shard logic
// ─────────────────────────────────────────────────────────────────────────

pub fn shard_knot(input_path: &Path, output_dir: &Path, spec: &str) -> Result<Manifest, String> {
    let file =
        File::open(input_path).map_err(|e| format!("open {}: {}", input_path.display(), e))?;
    let mmap = unsafe { Mmap::map(&file).map_err(|e| e.to_string())? };

    if mmap.len() < 11 || &mmap[0..4] != b"KNOT" {
        return Err("input is not a KNOT file".into());
    }
    let version_le: [u8; 2] = [mmap[4], mmap[5]];

    let mut meta_len_bytes = [0u8; 4];
    meta_len_bytes.copy_from_slice(&mmap[6..10]);
    let metadata_length = u32::from_le_bytes(meta_len_bytes) as usize;
    let aligned = (10 + metadata_length + 3) & !3;
    let codec_marker = mmap[aligned];
    let payload_offset = aligned + 1;

    let metadata_str = std::str::from_utf8(&mmap[10..10 + metadata_length])
        .map_err(|e| format!("metadata utf8: {}", e))?;
    let metadata_val: serde_json::Value =
        serde_json::from_str(metadata_str).map_err(|e| format!("metadata json: {}", e))?;

    // Parse tensors WITHOUT stripping `.bin` so the writer can echo the source
    // tensor map keys verbatim. (The runtime loader strips `.bin`; sharding is
    // a deploy-time identity transform, so we keep the original keys.)
    let source_tensors = parse_tensors_raw(&metadata_val)?;
    let config = metadata_val.get("config").cloned();
    let num_layers = config
        .as_ref()
        .and_then(|c| c.get("num_layers"))
        .and_then(|v| v.as_u64())
        .ok_or("knot metadata missing config.num_layers")? as usize;

    let shards = parse_shard_spec(spec, num_layers)?;

    fs::create_dir_all(output_dir)
        .map_err(|e| format!("create {}: {}", output_dir.display(), e))?;

    let payload = &mmap[payload_offset..];

    let mut manifest_entries = Vec::with_capacity(shards.len());
    for (idx, sspec) in shards.iter().enumerate() {
        let names = tensors_for_shard(sspec, &source_tensors);
        let (meta_bytes, layout) = build_shard_metadata(&metadata_val, &source_tensors, &names);
        let filename = format!("shard-{}-{}.knot", idx, sspec.role.as_str());
        let out_path = output_dir.join(&filename);
        write_shard_file(
            &out_path,
            version_le,
            codec_marker,
            &meta_bytes,
            &layout,
            payload,
        )?;
        manifest_entries.push(ShardManifestEntry {
            filename,
            start_layer: sspec.start_layer,
            end_layer: sspec.end_layer,
            role: sspec.role.as_str().to_string(),
            tensor_names: names,
        });
    }

    let source_filename = input_path
        .file_name()
        .map(|s| s.to_string_lossy().into_owned())
        .unwrap_or_else(|| input_path.display().to_string());

    let manifest = Manifest {
        source: source_filename,
        config,
        shards: manifest_entries,
    };

    let manifest_path = output_dir.join("manifest.json");
    let manifest_bytes =
        serde_json::to_vec_pretty(&manifest).map_err(|e| format!("serialize manifest: {}", e))?;
    fs::write(&manifest_path, manifest_bytes).map_err(|e| format!("write manifest: {}", e))?;

    Ok(manifest)
}

/// Like `loader::parse_tensors` but preserves original keys (no `.bin` strip).
/// Keeps shard metadata byte-identical to the source for tensors it carries.
fn parse_tensors_raw(
    metadata_val: &serde_json::Value,
) -> Result<HashMap<String, TensorInfo>, String> {
    let mut out = HashMap::new();
    let tensors = metadata_val
        .get("tensors")
        .and_then(|v| v.as_object())
        .ok_or("metadata missing `tensors` object")?;
    for (k, v) in tensors {
        let info: TensorInfo =
            serde_json::from_value(v.clone()).map_err(|e| format!("tensor {}: {}", k, e))?;
        out.insert(k.clone(), info);
    }
    Ok(out)
}

// ─────────────────────────────────────────────────────────────────────────
// main
// ─────────────────────────────────────────────────────────────────────────

fn main() {
    let args = match parse_args() {
        Ok(a) => a,
        Err(e) => {
            eprintln!("[shard-knot] arg error: {}", e);
            std::process::exit(2);
        }
    };

    match shard_knot(&args.input, &args.output_dir, &args.shards) {
        Ok(manifest) => {
            // BTreeMap-style sorted summary so output is deterministic for CI logs.
            let mut by_role: BTreeMap<String, Vec<&ShardManifestEntry>> = BTreeMap::new();
            for s in &manifest.shards {
                by_role.entry(s.role.clone()).or_default().push(s);
            }
            eprintln!(
                "[shard-knot] wrote {} shard(s) + manifest.json to {}",
                manifest.shards.len(),
                args.output_dir.display()
            );
            for s in &manifest.shards {
                eprintln!(
                    "  {}  layers [{}, {})  {} tensors",
                    s.filename,
                    s.start_layer,
                    s.end_layer,
                    s.tensor_names.len()
                );
            }
        }
        Err(e) => {
            eprintln!("[shard-knot] error: {}", e);
            std::process::exit(1);
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────
// Tests
// ─────────────────────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;
    use std::io::Read;

    fn ti(off: u64, len: u64) -> TensorInfo {
        TensorInfo {
            offset: off,
            length: len,
            tensor_type: "Q8_0".into(),
            shape: None,
        }
    }

    #[test]
    fn residency_handles_bin_suffix_and_tied_embeddings() {
        // Real knots name tensors with a `.bin` suffix and TIE output_weight to
        // token_embd (so output_weight is absent). The residency must still place
        // the embedding in the entry shard (for /embed) and BOTH the final norm
        // and the tied embedding in the exit shard (for /lm-head).
        let mut md: HashMap<String, TensorInfo> = HashMap::new();
        md.insert("token_embd_weight.bin".into(), ti(0, 32));
        md.insert("output_norm_weight.bin".into(), ti(32, 8));
        for l in 0..4u64 {
            md.insert(format!("blk_{}_attn_q_weight.bin", l), ti(40 + l, 16));
            md.insert(format!("blk_{}_ffn_down_weight.bin", l), ti(60 + l, 24));
        }
        // no output_weight.bin -> tied embedding

        let entry = ShardSpec {
            start_layer: 0,
            end_layer: 2,
            role: ShardRole::Entry,
        };
        let exit = ShardSpec {
            start_layer: 2,
            end_layer: 4,
            role: ShardRole::Exit,
        };

        let e = tensors_for_shard(&entry, &md);
        assert!(
            e.contains(&"token_embd_weight.bin".to_string()),
            "entry must carry the embedding for /embed (was the .bin-suffix bug)"
        );
        assert!(
            e.iter().any(|n| n.starts_with("blk_0_")) && e.iter().any(|n| n.starts_with("blk_1_"))
        );
        assert!(
            !e.iter().any(|n| n.starts_with("blk_2_")),
            "entry must not carry out-of-range layers"
        );
        assert!(!e.contains(&"output_norm_weight.bin".to_string()));

        let x = tensors_for_shard(&exit, &md);
        assert!(
            x.contains(&"output_norm_weight.bin".to_string()),
            "exit needs the final norm"
        );
        assert!(
            x.contains(&"token_embd_weight.bin".to_string()),
            "tied embedding: the exit shard's /lm-head must carry token_embd"
        );
        assert!(
            x.iter().any(|n| n.starts_with("blk_2_")) && x.iter().any(|n| n.starts_with("blk_3_"))
        );
        assert!(
            !x.iter().any(|n| n.starts_with("blk_0_")),
            "exit must not carry out-of-range layers"
        );
    }

    /// Build an in-memory knot with `num_layers` layers, hidden_dim = 8.
    /// Each tensor's bytes are a deterministic ramp so we can verify byte-exact
    /// reconstruction after sharding.
    fn synth_knot(path: &Path, num_layers: usize) -> Vec<u8> {
        // Tensor list: token_embd_weight, output_norm_weight, output_weight,
        // and per-layer blk_L_attn_q_weight + blk_L_ffn_down_weight (two each).
        // Sentinel sizes per tensor; small but distinct.
        let mut tensors: Vec<(String, usize)> = Vec::new();
        tensors.push(("token_embd_weight".into(), 32));
        for l in 0..num_layers {
            tensors.push((format!("blk_{}_attn_q_weight", l), 16 + l));
            tensors.push((format!("blk_{}_ffn_down_weight", l), 24 + l));
        }
        tensors.push(("output_norm_weight".into(), 8));
        tensors.push(("output_weight".into(), 32));

        // Compute sequential offsets and total payload size.
        let mut payload: Vec<u8> = Vec::new();
        let mut tensor_meta = serde_json::Map::new();
        for (name, len) in &tensors {
            let offset = payload.len();
            // Distinct ramp per tensor: byte value = (name_len + i) % 251.
            let seed = (name.len() as u8).wrapping_add(13);
            for i in 0..*len {
                payload.push(seed.wrapping_add(i as u8));
            }
            let mut tinfo = serde_json::Map::new();
            tinfo.insert("offset".into(), serde_json::Value::from(offset));
            tinfo.insert("length".into(), serde_json::Value::from(*len));
            tinfo.insert("type".into(), serde_json::Value::from("F32".to_string()));
            tensor_meta.insert(name.clone(), serde_json::Value::Object(tinfo));
        }

        let config = serde_json::json!({
            "hidden_dim": 8,
            "num_layers": num_layers,
            "num_heads": 2,
            "num_kv_heads": 2,
            "head_dim": 4,
            "intermediate_size": 16,
            "vocab_size": 32,
            "rms_norm_eps": 1.0e-5,
            "rope_theta": 10000.0
        });

        let metadata = serde_json::json!({
            "name": "synth-test",
            "codec": "bitwise-fp64",
            "config": config,
            "tensors": serde_json::Value::Object(tensor_meta),
        });
        let metadata_bytes = serde_json::to_vec(&metadata).unwrap();

        // Assemble file bytes.
        let mut file_bytes: Vec<u8> = Vec::new();
        file_bytes.extend_from_slice(b"KNOT");
        file_bytes.extend_from_slice(&1u16.to_le_bytes()); // version
        file_bytes.extend_from_slice(&(metadata_bytes.len() as u32).to_le_bytes());
        file_bytes.extend_from_slice(&metadata_bytes);
        let unpadded = 10 + metadata_bytes.len();
        let aligned = (unpadded + 3) & !3;
        file_bytes.extend(std::iter::repeat(0u8).take(aligned - unpadded));
        file_bytes.push(0xF6); // arbitrary codec marker; round-trip preserves it
        file_bytes.extend_from_slice(&payload);

        fs::write(path, &file_bytes).unwrap();
        payload
    }

    fn read_shard_metadata(path: &Path) -> serde_json::Value {
        let mut f = File::open(path).unwrap();
        let mut buf = Vec::new();
        f.read_to_end(&mut buf).unwrap();
        assert_eq!(&buf[0..4], b"KNOT", "magic");
        let mut meta_len_bytes = [0u8; 4];
        meta_len_bytes.copy_from_slice(&buf[6..10]);
        let meta_len = u32::from_le_bytes(meta_len_bytes) as usize;
        serde_json::from_slice(&buf[10..10 + meta_len]).unwrap()
    }

    fn read_shard_payload(path: &Path) -> Vec<u8> {
        let mut f = File::open(path).unwrap();
        let mut buf = Vec::new();
        f.read_to_end(&mut buf).unwrap();
        let mut meta_len_bytes = [0u8; 4];
        meta_len_bytes.copy_from_slice(&buf[6..10]);
        let meta_len = u32::from_le_bytes(meta_len_bytes) as usize;
        let aligned = (10 + meta_len + 3) & !3;
        let payload_off = aligned + 1; // skip codec marker
        buf[payload_off..].to_vec()
    }

    fn read_shard_codec(path: &Path) -> u8 {
        let mut f = File::open(path).unwrap();
        let mut buf = Vec::new();
        f.read_to_end(&mut buf).unwrap();
        let mut meta_len_bytes = [0u8; 4];
        meta_len_bytes.copy_from_slice(&buf[6..10]);
        let meta_len = u32::from_le_bytes(meta_len_bytes) as usize;
        let aligned = (10 + meta_len + 3) & !3;
        buf[aligned]
    }

    #[test]
    fn parse_shard_spec_happy_path() {
        let s = parse_shard_spec("0..1:entry,2..3:exit", 4).unwrap();
        assert_eq!(s.len(), 2);
        assert_eq!(s[0].start_layer, 0);
        assert_eq!(s[0].end_layer, 2); // inclusive 0..1 -> [0, 2)
        assert_eq!(s[0].role, ShardRole::Entry);
        assert_eq!(s[1].start_layer, 2);
        assert_eq!(s[1].end_layer, 4);
        assert_eq!(s[1].role, ShardRole::Exit);
    }

    #[test]
    fn parse_shard_spec_rejects_gap() {
        let err = parse_shard_spec("0..0:entry,2..3:exit", 4).unwrap_err();
        assert!(err.contains("not contiguous"), "{}", err);
    }

    #[test]
    fn parse_shard_spec_rejects_missing_entry() {
        let err = parse_shard_spec("0..1:mid,2..3:exit", 4).unwrap_err();
        assert!(err.contains("entry"), "{}", err);
    }

    #[test]
    fn parse_shard_spec_rejects_missing_exit() {
        let err = parse_shard_spec("0..1:entry,2..3:mid", 4).unwrap_err();
        assert!(err.contains("exit"), "{}", err);
    }

    #[test]
    fn shards_split_and_recombine_byte_exact() {
        let tmp = std::env::temp_dir().join(format!("shard-knot-test-{}", std::process::id()));
        let _ = fs::remove_dir_all(&tmp);
        fs::create_dir_all(&tmp).unwrap();
        let knot_path = tmp.join("synth.knot");
        let original_payload = synth_knot(&knot_path, 4);

        let out_dir = tmp.join("shards");
        // CLI inclusive end: layers 0..1 = [0,2), 2..3 = [2,4)
        let manifest = shard_knot(&knot_path, &out_dir, "0..1:entry,2..3:exit").unwrap();
        assert_eq!(manifest.shards.len(), 2);

        // Codec marker preserved.
        for s in &manifest.shards {
            let p = out_dir.join(&s.filename);
            assert_eq!(read_shard_codec(&p), 0xF6, "codec marker preserved");
        }

        // Manifest.json exists and parses.
        assert!(out_dir.join("manifest.json").is_file());

        // Entry shard: must contain token_embd_weight + blk_0_*, blk_1_*.
        let entry = &manifest.shards[0];
        assert_eq!(entry.role, "entry");
        assert!(entry
            .tensor_names
            .contains(&"token_embd_weight".to_string()));
        assert!(entry
            .tensor_names
            .contains(&"blk_0_attn_q_weight".to_string()));
        assert!(entry
            .tensor_names
            .contains(&"blk_1_ffn_down_weight".to_string()));
        assert!(!entry.tensor_names.iter().any(|n| n.starts_with("blk_2_")));
        assert!(!entry.tensor_names.contains(&"output_weight".to_string()));

        // Exit shard: must contain blk_2_*, blk_3_*, output_norm_weight, output_weight.
        let exit = &manifest.shards[1];
        assert_eq!(exit.role, "exit");
        assert!(exit
            .tensor_names
            .contains(&"blk_2_attn_q_weight".to_string()));
        assert!(exit
            .tensor_names
            .contains(&"blk_3_ffn_down_weight".to_string()));
        assert!(exit
            .tensor_names
            .contains(&"output_norm_weight".to_string()));
        assert!(exit.tensor_names.contains(&"output_weight".to_string()));
        assert!(!exit.tensor_names.contains(&"token_embd_weight".to_string()));

        // Each shard parses as valid JSON metadata, has correct config echo,
        // and tensor offsets are sequential (cursor matches sum-of-lengths).
        for s in &manifest.shards {
            let meta = read_shard_metadata(&out_dir.join(&s.filename));
            let cfg = meta.get("config").unwrap();
            assert_eq!(cfg.get("num_layers").unwrap().as_u64().unwrap(), 4);
            assert_eq!(cfg.get("hidden_dim").unwrap().as_u64().unwrap(), 8);
            let tmap = meta.get("tensors").unwrap().as_object().unwrap();
            let mut expected_offset = 0u64;
            // Iterate in the manifest's tensor_names order (lexicographic, the
            // same order the writer used).
            for n in &s.tensor_names {
                let t = tmap.get(n).unwrap();
                assert_eq!(t.get("offset").unwrap().as_u64().unwrap(), expected_offset);
                let len = t.get("length").unwrap().as_u64().unwrap();
                expected_offset += len;
            }
        }

        // Deep correctness: stitching the source bytes corresponding to each
        // shard's tensor list (in shard order) equals the shard payload.
        // This proves the writer copied the right byte ranges.
        let original_meta = read_shard_metadata(&knot_path);
        let original_tensors = original_meta.get("tensors").unwrap().as_object().unwrap();

        for s in &manifest.shards {
            let mut expected_payload: Vec<u8> = Vec::new();
            for n in &s.tensor_names {
                let info = original_tensors.get(n).unwrap();
                let off = info.get("offset").unwrap().as_u64().unwrap() as usize;
                let len = info.get("length").unwrap().as_u64().unwrap() as usize;
                expected_payload.extend_from_slice(&original_payload[off..off + len]);
            }
            let actual = read_shard_payload(&out_dir.join(&s.filename));
            assert_eq!(
                actual.len(),
                expected_payload.len(),
                "payload length mismatch for {}",
                s.filename
            );
            assert_eq!(
                actual, expected_payload,
                "payload bytes mismatch for {}",
                s.filename
            );
        }

        // Cleanup.
        let _ = fs::remove_dir_all(&tmp);
    }

    #[test]
    fn three_way_split_with_mid() {
        let tmp = std::env::temp_dir().join(format!("shard-knot-test-mid-{}", std::process::id()));
        let _ = fs::remove_dir_all(&tmp);
        fs::create_dir_all(&tmp).unwrap();
        let knot_path = tmp.join("synth.knot");
        synth_knot(&knot_path, 6);
        let out_dir = tmp.join("shards");
        let manifest = shard_knot(&knot_path, &out_dir, "0..1:entry,2..3:mid,4..5:exit").unwrap();
        assert_eq!(manifest.shards.len(), 3);
        assert_eq!(manifest.shards[1].role, "mid");
        // Mid shard owns only blk_2_*, blk_3_*; no embed, no output.
        let mid = &manifest.shards[1];
        assert!(!mid.tensor_names.contains(&"token_embd_weight".to_string()));
        assert!(!mid.tensor_names.contains(&"output_weight".to_string()));
        assert!(mid
            .tensor_names
            .iter()
            .all(|n| n.starts_with("blk_2_") || n.starts_with("blk_3_")));
        let _ = fs::remove_dir_all(&tmp);
    }
}
